import{_ as e,o as l,c as s,ak as r}from"./chunks/framework.BHDkgpnK.js";const f=JSON.parse('{"title":"KossJS 版本管理规范","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/version/version-overview.md","filePath":"zh/guide/version/version-overview.md","lastUpdated":0}'),n={name:"zh/guide/version/version-overview.md"};function g(o,t,a,i,d,m){return l(),s("div",null,[...t[0]||(t[0]=[r('<h1 id="kossjs-版本管理规范" tabindex="-1">KossJS 版本管理规范 <a class="header-anchor" href="#kossjs-版本管理规范" aria-label="Permalink to “KossJS 版本管理规范”">​</a></h1><p><strong>版本：1.0.0</strong><strong>最后修订日期：</strong> 2026-04-12</p><p>本文档定义了 KossJS 项目的版本号管理规则，旨在确保版本演进清晰、一致，并促进项目与依赖项之间的兼容性理解。本规范基于 <a href="https://semver.org/" target="_blank" rel="noreferrer">语义化版本 2.0.0</a> 制定。</p><h2 id="_1-核心术语与要求级别" tabindex="-1">1. 核心术语与要求级别 <a class="header-anchor" href="#_1-核心术语与要求级别" aria-label="Permalink to “1. 核心术语与要求级别”">​</a></h2><p>本文档中，&quot;必须&quot;（MUST）、&quot;不得&quot;（MUST NOT）、&quot;要求&quot;（REQUIRED）、&quot;建议&quot;（RECOMMENDED）、&quot;可以&quot;（MAY）、&quot;可选&quot;（OPTIONAL）等关键词，按 <a href="https://tools.ietf.org/html/rfc2119" target="_blank" rel="noreferrer">RFC 2119</a> 的表述进行解释。</p><h2 id="_2-版本号格式" tabindex="-1">2. 版本号格式 <a class="header-anchor" href="#_2-版本号格式" aria-label="Permalink to “2. 版本号格式”">​</a></h2><p>KossJS 的版本号<strong>必须</strong>遵循以下格式：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&lt;主版本号&gt;.&lt;次版本号&gt;.&lt;修订号&gt;[-&lt;预发布标识符&gt;.&lt;预发布编号&gt;][+&lt;构建元数据&gt;]</span></span></code></pre></div><p>各部分说明如下：</p><table tabindex="0"><thead><tr><th style="text-align:left;">组成部分</th><th style="text-align:left;">名称</th><th style="text-align:left;">必需性</th><th style="text-align:left;">规则与示例</th></tr></thead><tbody><tr><td style="text-align:left;"><em><strong>&lt;主版本号&gt;</strong></em></td><td style="text-align:left;">Major</td><td style="text-align:left;"><strong>必需</strong></td><td style="text-align:left;">非负整数，不得包含前导零。例如：<em><strong>0</strong></em>，<em><strong>1</strong></em>，<em><strong>42</strong></em>。</td></tr><tr><td style="text-align:left;"><em><strong>&lt;次版本号&gt;</strong></em></td><td style="text-align:left;">Minor</td><td style="text-align:left;"><strong>必需</strong></td><td style="text-align:left;">非负整数，不得包含前导零。例如：<em><strong>0</strong></em>，<em><strong>1</strong></em>，<em><strong>23</strong></em>。</td></tr><tr><td style="text-align:left;"><em><strong>&lt;修订号&gt;</strong></em></td><td style="text-align:left;">Patch</td><td style="text-align:left;"><strong>必需</strong></td><td style="text-align:left;">非负整数，不得包含前导零。例如：<em><strong>0</strong></em>，<em><strong>1</strong></em>，<em><strong>7</strong></em>。</td></tr><tr><td style="text-align:left;"><em><strong>-&lt;预发布标识符&gt;.&lt;预发布编号&gt;</strong></em></td><td style="text-align:left;">Pre-release</td><td style="text-align:left;">可选</td><td style="text-align:left;">标识符为小写字母字符串，编号为正整数，且不得包含前导零。例如：<em><strong>-dev.1</strong></em>，<em><strong>-rc.3</strong></em>。</td></tr><tr><td style="text-align:left;"><em><strong>+&lt;构建元数据&gt;</strong></em></td><td style="text-align:left;">Build metadata</td><td style="text-align:left;">可选</td><td style="text-align:left;">由字母、数字、连字符组成的字符串。例如：<em><strong>+20250226</strong></em>，<em><strong>+nightly.2025.03</strong></em>。</td></tr></tbody></table><p><strong>有效的版本号示例</strong>：</p><ul><li><em><strong>1.2.3</strong></em></li><li><em><strong>2.0.0-dev.1</strong></em></li><li><em><strong>0.1.0-beta.2+20250226</strong></em></li></ul><h2 id="_3-核心版本-x-y-z-的递增规则" tabindex="-1">3. 核心版本（X.Y.Z）的递增规则 <a class="header-anchor" href="#_3-核心版本-x-y-z-的递增规则" aria-label="Permalink to “3. 核心版本（X.Y.Z）的递增规则”">​</a></h2><p>版本号的核心部分（&lt;主版本号&gt;.&lt;次版本号&gt;.&lt;修订号&gt;）<strong>必须</strong>始终根据以下规则递增。</p><ol><li><strong>主版本号（X）</strong>：当进行了<strong>不兼容</strong>的 API 或核心功能变更时递增。</li><li><strong>次版本号（Y）</strong>：当以<strong>向后兼容</strong>的方式添加新功能时递增。</li><li><strong>修订号（Z）</strong>：当进行了<strong>向后兼容</strong>的问题修复时递增。</li></ol><h2 id="_4-预发布版本阶段" tabindex="-1">4. 预发布版本阶段 <a class="header-anchor" href="#_4-预发布版本阶段" aria-label="Permalink to “4. 预发布版本阶段”">​</a></h2><p>在进入正式版之前，或为正式版发布候选时，<strong>必须</strong>使用预发布后缀来标识其成熟度。KossJS 定义以下预发布阶段：</p><table tabindex="0"><thead><tr><th style="text-align:left;">阶段</th><th style="text-align:left;">标识符</th><th style="text-align:left;">版本号示例</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开发版</strong></td><td style="text-align:left;"><em><strong>dev</strong></em></td><td style="text-align:left;"><em><strong>0.1.0-dev.1</strong></em></td><td style="text-align:left;">活跃开发中的内部快照，功能不完整或不稳定，仅供核心开发者使用。</td></tr><tr><td style="text-align:left;"><strong>内部测试版</strong></td><td style="text-align:left;"><em><strong>internal</strong></em></td><td style="text-align:left;"><em><strong>0.1.0-internal.1</strong></em></td><td style="text-align:left;">完成部分功能，交付给内部测试团队验证，可能存在较多缺陷。</td></tr><tr><td style="text-align:left;"><strong>Alpha 测试版</strong></td><td style="text-align:left;"><em><strong>alpha</strong></em></td><td style="text-align:left;"><em><strong>0.1.0-alpha.1</strong></em></td><td style="text-align:left;">核心功能基本完成，面向有限的外部测试者收集早期反馈，预期存在较多问题。</td></tr><tr><td style="text-align:left;"><strong>Beta 测试版</strong></td><td style="text-align:left;"><em><strong>beta</strong></em></td><td style="text-align:left;"><em><strong>0.1.0-beta.1</strong></em></td><td style="text-align:left;">功能已完整，主要缺陷已修复，面向更广泛的用户进行公开测试。</td></tr><tr><td style="text-align:left;"><strong>候选发布版</strong></td><td style="text-align:left;"><em><strong>rc</strong></em></td><td style="text-align:left;"><em><strong>0.1.0-rc.1</strong></em></td><td style="text-align:left;">接近正式版本，若无重大问题，将直接作为正式版发布。</td></tr></tbody></table><p><strong>预发布规则</strong>：</p><ul><li>预发布标识符<strong>必须</strong>为小写字母。</li><li>预发布编号<strong>必须</strong>为从 <em><strong>1</strong></em> 开始递增的正整数。</li><li>当版本从一个阶段演进到下一个阶段时，编号<strong>必须</strong>重置为 <em><strong>1</strong></em>。</li></ul><h2 id="_5-版本优先级" tabindex="-1">5. 版本优先级 <a class="header-anchor" href="#_5-版本优先级" aria-label="Permalink to “5. 版本优先级”">​</a></h2><p>版本优先级<strong>必须</strong>严格按语义化版本规则确定：</p><ol><li>版本号按顺序比较：主版本号、次版本号、修订号。数值越大，版本越新。</li><li>正式版本（无预发布后缀）的优先级<strong>总是高于</strong>任何预发布版本。例如：<em><strong>1.0.0</strong></em> &gt; <em><strong>1.0.0-rc.1</strong></em>。</li><li>对于有相��核心版本号的预发布版本，其优先级由标识符决定。标识符按<strong>字典序</strong>比较：<em><strong>dev</strong></em> &lt; <em><strong>internal</strong></em> &lt; <em><strong>alpha</strong></em> &lt; <em><strong>beta</strong></em> &lt; <em><strong>rc</strong></em>。</li></ol><h2 id="_6-规范的修订" tabindex="-1">6. 规范的修订 <a class="header-anchor" href="#_6-规范的修订" aria-label="Permalink to “6. 规范的修订”">​</a></h2><p>本规范自身将使用语义化版本进行管理。对规范的任何修订（包括规则的澄清或变更），都必须更新此文档的版本号，并记录于下：</p><table tabindex="0"><thead><tr><th style="text-align:left;">版本</th><th style="text-align:left;">日期</th><th style="text-align:left;">修订说明</th><th style="text-align:left;">作者</th></tr></thead><tbody><tr><td style="text-align:left;">0.1.0-dev.2</td><td style="text-align:left;">2026/04/12</td><td style="text-align:left;">初始版本，基于 SemVer 2.0.0 建立</td><td style="text-align:left;">Sxxyrry</td></tr></tbody></table>',26)])])}const x=e(n,[["render",g]]);export{f as __pageData,x as default};
